const d = $json.body || $json;

if (!d.email || !d.company_name) throw new Error('Missing required fields: email or company_name');

return {
  json: {
    forwarder_id: d.forwarder_id || '',
    company_name: d.company_name,
    contact_person: d.contact_person || 'N/A',
    email: d.email,
    company_email: d.company_email || d.email,
    phone: d.phone || 'N/A',
    whatsapp: d.whatsapp || d.phone || 'N/A',
    country: d.country || 'N/A',
    specializations: Array.isArray(d.specializations) ? d.specializations.join(', ') : (d.specializations || 'N/A'),
    routes: Array.isArray(d.routes) ? d.routes.join(', ') : (d.routes || 'N/A'),
    tax_id: d.tax_id || 'N/A',
    website: d.website || 'N/A',
    document_url: d.document_url || '',
    logo_url: d.logo_url || '',
    registered_at: new Date().toISOString()
  }
};

const d = $('Code - Parse & Normalize').first().json;

const message = `*New Partner Application*

*Company:* ${d.company_name}
*Contact:* ${d.contact_person}
*Email:* ${d.email}
*Phone:* ${d.phone}
*WhatsApp:* ${d.whatsapp}
*Country:* ${d.country}
*Specializations:* ${d.specializations}
*Routes:* ${d.routes}
*Tax ID:* ${d.tax_id}
*Partner ID:* ${d.forwarder_id}

Review in admin panel: https://cargolink.sa/admin`;

return { json: { message, phone: d.whatsapp } };

const d = $('Code - Parse & Normalize').first().json;

const emailBody = `<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head><body style="margin:0;padding:0;background:#f0f4f8;font-family:-apple-system,BlinkMacSystemFont,system-ui,Arial,sans-serif;"><table width="100%" cellpadding="0" cellspacing="0" border="0" style="background:#f0f4f8;"><tr><td align="center" style="padding:32px 16px;"><table cellpadding="0" cellspacing="0" border="0" style="max-width:600px;width:100%;background:#ffffff;border-radius:12px;overflow:hidden;box-shadow:0 4px 24px rgba(0,0,0,0.09);"><tr><td style="background:#1a1a1a;padding:36px 32px 28px;text-align:center;"><img src="https://cargolink.sa/cargolink.png" alt="CargoLink" width="160" style="display:block;margin:0 auto 16px;max-width:160px;height:auto;" /><h1 style="margin:0 0 8px;font-size:24px;font-weight:900;color:#ffffff;letter-spacing:1px;">Application Received</h1><p style="margin:0;font-size:14px;color:rgba(255,255,255,0.7);">CargoLink Partner Network</p></td></tr><tr><td style="padding:36px 32px;"><p style="margin:0 0 16px;font-size:15px;color:#333;">Dear <strong>${d.contact_person}</strong>,</p><p style="margin:0 0 20px;font-size:15px;color:#333;">Thank you for applying to join the <strong>CargoLink freight partner network</strong>. We have received your application for <strong>${d.company_name}</strong> and it is currently under review.</p><table width="100%" cellpadding="0" cellspacing="0" border="0" style="background:#f5f5f5;border-left:4px solid #374151;border-radius:6px;margin:0 0 24px;"><tr><td style="padding:20px;"><p style="margin:4px 0;font-size:14px;color:#333;"><strong>Application Reference:</strong> ${d.forwarder_id}</p><p style="margin:4px 0;font-size:14px;color:#333;"><strong>Company:</strong> ${d.company_name}</p><p style="margin:4px 0;font-size:14px;color:#333;"><strong>Country:</strong> ${d.country}</p><p style="margin:4px 0;font-size:14px;color:#333;"><strong>Submitted:</strong> ${new Date().toLocaleDateString('en-GB',{day:'numeric',month:'long',year:'numeric'})}</p></td></tr></table><p style="margin:0 0 12px;font-size:15px;font-weight:700;color:#1a1a1a;">What happens next?</p><table width="100%" cellpadding="0" cellspacing="0" border="0" style="background:#f9f9f9;border-radius:8px;margin:0 0 24px;"><tr><td style="padding:20px 20px 20px 24px;"><p style="margin:0 0 10px;font-size:14px;color:#444;">1. Our team will verify your company details and documentation.</p><p style="margin:0 0 10px;font-size:14px;color:#444;">2. You will receive a decision by email within 2–3 business days.</p><p style="margin:0 0 10px;font-size:14px;color:#444;">3. If approved, you will get your Partner ID and access to the Forwarder Portal.</p><p style="margin:0;font-size:14px;color:#444;">4. If we need additional information, we will reach out directly.</p></td></tr></table><p style="margin:0;font-size:13px;color:#888;">Questions? Reply to this email or visit our <a href="https://cargolink.sa/help" style="color:#374151;">Help Center</a>.</p></td></tr><tr><td style="background:#f8f8f8;padding:20px 32px;text-align:center;border-top:1px solid #eee;"><p style="margin:0 0 4px;font-size:12px;color:#888;"><strong>CargoLink Platform</strong> — Connecting shippers with the world's best freight forwarders</p><p style="margin:0;font-size:11px;color:#aaa;">© 2025 CargoLink. All rights reserved.</p></td></tr></table></td></tr></table></body></html>`;

return { json: { ...d, email_body: emailBody } };
